const item = $input.item.json;
const companyName = item.company_name || '';
const jobTitle = item.job_title || '';
const location = item.location || '';
const jobUrl = item.job_url || '';
const jobDescription = item.job_description || '';
const userSkills = item.user_skills || '';
const techStack = item.tech_stack || '';
const jobRequirements = item.job_requirements || '';

const id = 'app-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);

const now = new Date();
const year = now.getFullYear().toString();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const appliedDate = year + '-' + month + '-' + day;

const folderName = day + '_' + companyName.replace(/[^a-zA-Z0-9]/g, '_') + '_' + jobTitle.replace(/[^a-zA-Z0-9]/g, '_');

return [{
  json: {
    application_id: id,
    company_name: companyName,
    job_title: jobTitle,
    location: location,
    job_url: jobUrl,
    job_description: jobDescription,
    user_skills: userSkills,
    tech_stack: techStack,
    job_requirements: jobRequirements,
    applied_date: appliedDate,
    year: year,
    month: month,
    day: day,
    folder_name: folderName
  }
}];

const tierData = $input.item.json;

// ATS keyword optimization: scan resume content for critical Israeli tech market keywords
const resumeText = (tierData.resume_content || '').toLowerCase();

const keywordCategories = {
  'Cloud Platforms': ['aws', 'ec2', 's3', 'lambda', 'rds', 'gcp', 'compute engine', 'cloud run', 'firestore', 'azure'],
  'Containerization': ['docker', 'kubernetes', 'k8s', 'helm', 'container'],
  'CI/CD': ['github actions', 'gitlab ci', 'jenkins', 'circleci', 'ci/cd', 'pipeline'],
  'Architecture': ['microservices', 'distributed', 'scalability', 'load balancing', 'system design', 'rest api', 'graphql'],
  'Databases': ['sql', 'nosql', 'redis', 'postgresql', 'mongodb', 'elasticsearch', 'database'],
  'Testing': ['jest', 'vitest', 'cypress', 'playwright', 'unit test', 'integration test', 'e2e', 'test coverage'],
  'Code Quality': ['typescript', 'eslint', 'solid', 'code review', 'type safety', 'linting'],
  'Monitoring': ['datadog', 'elk', 'observability', 'logging', 'prometheus', 'grafana', 'monitoring'],
  'DevOps': ['terraform', 'infrastructure as code', 'iac', 'ansible', 'devops']
};

const present = [];
const missing = [];

for (const [category, keywords] of Object.entries(keywordCategories)) {
  const found = keywords.filter(function(kw) { return resumeText.includes(kw); });
  const notFound = keywords.filter(function(kw) { return !resumeText.includes(kw); });
  if (found.length > 0) {
    present.push('**' + category + '**: ' + found.join(', '));
  }
  if (notFound.length > 0) {
    missing.push('**' + category + '**: ' + notFound.join(', '));
  }
}

const score = Math.round((present.length / (present.length + missing.length)) * 100);

const atsContent =
  '# ATS Keyword Analysis - ' + (tierData.company_name || '') + '\n\n' +
  '## ATS Score: ' + score + '%\n\n' +
  '## Keywords Present (' + present.length + ')\n' +
  present.map(function(k) { return '- ' + k; }).join('\n') + '\n\n' +
  '## Missing Keywords (' + missing.length + ') - ADD THESE\n' +
  missing.map(function(k) { return '- ' + k; }).join('\n') + '\n\n' +
  '## Recommendation\n' +
  (score < 50 ? 'CRITICAL: Resume needs significant ATS optimization before sending.' :
   score < 70 ? 'MODERATE: Add missing keywords naturally to improve ATS pass rate.' :
   'GOOD: Resume has strong ATS keyword coverage. Add remaining keywords where applicable.') + '\n';

return [{
  json: {
    ...tierData,
    ats_score: score,
    ats_keywords_present: present.length,
    ats_keywords_missing: missing.length,
    ats_content: atsContent,
    resume_content: (tierData.resume_content || '') + '\n\n---\n\n' + atsContent
  }
}];

const jobData = $input.item.json;

async function callOllama(prompt) {
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const resp = await $helpers.httpRequest({
        method: 'POST',
        url: 'http://ollama:11434/api/generate',
        headers: { 'Content-Type': 'application/json' },
        body: { model: 'llama3.2', prompt: prompt, stream: false },
      });
      return (resp && resp.response) ? resp.response : '[No response]';
    } catch (e) {
      if (attempt === 3) return '[Ollama Error: ' + e.message + ']';
      await new Promise(r => setTimeout(r, Math.pow(2, attempt) * 1000));
    }
  }
}

const introEmailPrompt =
  'You are a successful Israeli engineer/founder reaching out to hiring managers as a peer ' +
  '(not as a desperate job-seeker, but as someone confident they\'d be a good fit).\n\n' +
  'Your Task:\n' +
  '1. Respect Their Time - Maximum 4-5 sentences, clear value proposition in first 2 sentences\n' +
  '2. Personalization - Reference something SPECIFIC about them (tech decision, product feature, talk they gave)\n' +
  '   NOT: "I\'m impressed with your company" (too generic)\n' +
  '   YES: "I noticed you migrated to Kubernetes - that\'s exactly the infrastructure thinking I\'m passionate about"\n' +
  '3. Credibility in One Sentence - Prove you\'re not a junior, reference a recent relevant project/skill\n' +
  '4. Specific Ask - "Would you have 15 minutes for a quick chat about [specific topic]?"\n' +
  '5. Easy Out - "No pressure if timing doesn\'t work!" - shows confidence and respect\n\n' +
  'Template: [Personalized reference] [My credibility] [Specific ask] [Easy out]\n' +
  'Output: Complete cold email + 2-3 alternative versions + notes on what makes it likely to get a response\n\n' +
  'Company: ' + jobData.company_name + '\nJob Title: ' + jobData.job_title;

const followUpPrompt =
  'Create a follow-up email for ' + jobData.company_name + ' ' + jobData.job_title + ' position. ' +
  'Show genuine interest, reference previous contact/application. Build on introduction. ' +
  'Under 100 words. Be professional but personable.';

const companyResearchPrompt =
  'Research and provide detailed information about ' + jobData.company_name + '. ' +
  'Include: industry/sector, recent news and achievements, company size and growth, ' +
  'key decision-makers if known, company culture indicators, recent funding/partnerships, ' +
  'growth metrics, hiring trends. Format as comprehensive bullet-point analysis.';

const personalAnglePrompt =
  'Identify personal connection angles for contacting ' + jobData.company_name + ' for ' + jobData.job_title + '. ' +
  'Look for: alumni connections, shared interests or values, industry events, mutual LinkedIn connections, ' +
  'shared projects or open source, content they\'ve published, hiring manager information. ' +
  'Suggest specific outreach strategy for each angle.';

const introEmail = await callOllama(introEmailPrompt);
const followUp = await callOllama(followUpPrompt);
const companyResearch = await callOllama(companyResearchPrompt);
const personalAngle = await callOllama(personalAnglePrompt);

const coldEmailContent =
  '# Cold Outreach - ' + jobData.company_name + '\n\n' +
  '## Introduction Email\n\n' + introEmail + '\n\n---\n\n' +
  '## Follow-Up Email\n\n' + followUp + '\n';

const companyResearchContent =
  '# Company Research - ' + jobData.company_name + '\n\n' + companyResearch + '\n';

const personalAngleContent =
  '# Personal Connection Angles - ' + jobData.company_name + '\n\n' + personalAngle + '\n';

return [{
  json: {
    ...jobData,
    tier2_status: 'complete',
    cold_email_content: coldEmailContent,
    company_research_content: companyResearchContent,
    personal_angle_content: personalAngleContent
  }
}];

