  '2. Behavioral Questions (2-3): Reveal problem-solving, learning ability, collaboration, handling failure\n' +
  '3. Culture Fit & Growth - Questions specific to Israeli tech culture\n' +
  '4. Talking Points - What to emphasize about my background, how to frame weaknesses as growth areas\n' +
  '5. Questions YOU Should Ask Them (3-4 intelligent questions showing you understand the role)\n\n' +
  'Output: Question + model answer + explanation, "Why this works" + "Common mistakes to avoid"\n\n' +
  'Job Title: ' + jobData.job_title + '\nCompany: ' + jobData.company_name + '\nTech Stack: ' + jobData.tech_stack;

const talkingPointsPrompt =
  'You are a career coach and technical mentor helping me prepare talking points for interviews.\n\n' +
  'Your Task:\n' +
  '1. For This Specific Role - What are the 3-5 most relevant experiences/skills I should highlight?\n' +
  '2. Project Deep-Dives - For my 3 best projects: Problem -> Solution -> Impact\n' +
  '3. Addressing Gaps - Where might they ask tough questions? How to frame gaps authentically?\n' +
  '4. Company-Specific Talking Points - How do my experiences align with THEIR mission/tech stack?\n' +
  '5. Strength Positioning - Top 3 strengths for this role with evidence/metrics\n\n' +
  'Output: Bullet-point talking points, for each: the point + supporting story + how to deliver it naturally\n\n' +
  'Company: ' + jobData.company_name + '\nJob Title: ' + jobData.job_title;

const salaryPrompt =
  'You are a seasoned HR professional + engineer who understands both sides. ' +
  'You know Israeli market realities and what\'s negotiable.\n\n' +
  'Your Task:\n' +
  '1. Market Research & Benchmarking - salary range for this role + level in Israel (2026)\n' +
  '2. My Leverage Assessment - strongest negotiation points, unique skills\n' +
  '3. Total Compensation Breakdown - Base, equity/options, bonus, benefits, signing\n' +
  '4. Negotiation Scripts: "What\'s your expectation?" / "Best we can do is X" / "Can you start next week?"\n' +
  '5. Red Flags & Warnings - equity worth, benefits, flexibility\n' +
  '6. Walk-Away Point - minimum acceptable offer\n\n' +
  'Output: Market salary ranges, leverage assessment, script templates, red flags, total comp comparison\n\n' +
  'Job Title: ' + jobData.job_title + '\nLocation: ' + jobData.location;

const skillsGap = await callOllama(skillsGapPrompt);
const interviewQuestions = await callOllama(interviewQuestionsPrompt);
const talkingPoints = await callOllama(talkingPointsPrompt);
const salary = await callOllama(salaryPrompt);

const interviewPrepContent =
  '# Interview Preparation - ' + jobData.company_name + ' - ' + jobData.job_title + '\n\n' +
  '## Skills Gap Analysis\n\n' + skillsGap + '\n\n---\n\n' +
  '## Interview Questions & Answers\n\n' + interviewQuestions + '\n\n---\n\n' +
  '## Talking Points\n\n' + talkingPoints + '\n\n---\n\n' +
  '## Salary Guide & Negotiation\n\n' + salary + '\n';

return [{
  json: {
    ...jobData,
    tier3_status: 'complete',
    interview_prep_content: interviewPrepContent
  }
}];

const jobData = $input.item.json;

async function callOllama(prompt) {
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      const resp = await $helpers.httpRequest({
