// CHANGE #4: Real GitHub API call to fetch actual repos from odeliyach
let repoList = '';
let repoDetails = '';
try {
  const reposResp = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://api.github.com/users/odeliyach/repos?sort=updated&per_page=30&type=public',
    headers: {
      'Accept': 'application/vnd.github.v3+json',
      'User-Agent': 'n8n-job-search-portfolio'
    }
  });
  const repos = Array.isArray(reposResp) ? reposResp : [];
  repoList = repos.map(function(r) {
    return r.name + ' (language: ' + (r.language || 'N/A') + ', stars: ' + r.stargazers_count +
      ', updated: ' + r.updated_at.substring(0, 10) + '): ' + (r.description || 'No description');
  }).join('\n');
  repoDetails = repos.map(function(r) {
    return '- **' + r.name + '**: ' + (r.description || 'No description') +
      ' | Language: ' + (r.language || 'N/A') +
      ' | Stars: ' + r.stargazers_count +
      ' | Updated: ' + r.updated_at.substring(0, 10) +
      ' | URL: ' + r.html_url;
  }).join('\n');
} catch (e) {
  repoList = '[GitHub API Error: ' + e.message + ']';
  repoDetails = '[Could not fetch repos: ' + e.message + ']';
}

const projectSelectionPrompt =
  'From user\'s GitHub (username: odeliyach), identify and select the 5 projects most relevant to the job below.\n\n' +
  'ACTUAL GitHub repos from odeliyach (fetched via GitHub API):\n' + repoList + '\n\n' +
  'Job Title: ' + jobData.job_title + '\n' +
  'Company: ' + jobData.company_name + '\n' +
  'Job Description: ' + jobData.job_description + '\n\n' +
  'For each selected project explain: why it\'s relevant, technical skills match, complexity, business impact, ' +
  'recency, documentation quality. Be specific about the actual repo names listed above.';

const metricsPrompt =
  'For the selected GitHub projects from odeliyach, create quantifiable metrics showing impact. ' +
  'For each project include: performance improvements (%, ms, throughput), user growth metrics, ' +
  'cost savings, engagement metrics, scalability metrics, code quality metrics. ' +
  'Use specific numbers and percentages. Base on the actual repos: ' + repoList;

const projectContextPrompt =
  'For each selected project from odeliyach\'s GitHub provide: original objectives/problem solved, ' +
  'technical challenges faced, specific role and responsibilities, technologies/tools used, ' +
  'impact achieved, lessons learned. Be detailed and business-focused. ' +
  'Actual repos to analyze: ' + repoList;

const githubStrategyPrompt =
  'Provide strategies to improve GitHub visibility for odeliyach\'s projects to attract ' + jobData.company_name + ' attention. ' +
  'Include: README improvements, demo links/videos, contribution stats highlighting, deployment links, ' +
  'relevant badges, documentation enhancement, community engagement, GitHub profile optimization. ' +
  'Focus on these actual repos: ' + repoList;

const projectSelection = await callOllama(projectSelectionPrompt);
const metrics = await callOllama(metricsPrompt);
const projectContext = await callOllama(projectContextPrompt);
const githubStrategy = await callOllama(githubStrategyPrompt);

const portfolioContent =
  '# Portfolio Matching - ' + jobData.company_name + ' - ' + jobData.job_title + '\n\n' +
  '## GitHub Repositories (odeliyach - fetched ' + new Date().toISOString().substring(0, 10) + ')\n\n' +
  repoDetails + '\n\n---\n\n' +
  '## Project Selection (Most Relevant to Role)\n\n' + projectSelection + '\n\n---\n\n' +
  '## Project Metrics\n\n' + metrics + '\n\n---\n\n' +
  '## Project Context\n\n' + projectContext + '\n\n---\n\n' +
  '## GitHub Visibility Strategy\n\n' + githubStrategy + '\n';

return [{
  json: {
    ...jobData,
    tier4_status: 'complete',
    portfolio_content: portfolioContent,
    github_repos_fetched: repoList.substring(0, 500)
  }
}];

const jobData = $input.item.json;

const now = new Date();
const fu1Date = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const fu2Date = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const fu3Date = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const fu4Date = new Date(now.getTime() + 90 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

const trackingContent =
  '# Application Tracking: ' + jobData.company_name + ' - ' + jobData.job_title + '\n\n' +
  '## Status\n' +
  '- **Current Status:** Active\n' +
  '- **Applied:** ' + jobData.applied_date + '\n' +
  '- **Application ID:** ' + jobData.application_id + '\n' +
  '- **Location:** ' + jobData.location + '\n' +
  '- **Job URL:** ' + jobData.job_url + '\n\n' +
  '## Follow-Up Schedule\n' +
  '- [ ] Day 3 check-in: ' + fu1Date + '\n' +
  '- [ ] Day 7 follow-up: ' + fu2Date + '\n' +
  '- [ ] Day 30 check-in: ' + fu3Date + '\n' +
  '- [ ] 90-day check-in: ' + fu4Date + '\n\n' +
  '## Interview Stages\n' +
  '- [ ] Phone Screen\n' +
  '- [ ] Technical Interview\n' +
  '- [ ] Final Round\n\n' +
  '## Notes\n' +
  '_Add notes after each interaction_\n\n' +
  '## Contacts\n' +
  '- Recruiter: \n' +
  '- Hiring Manager: \n' +
  '- Referral: \n';

const analyticsContent =
  '# Analytics Update - ' + jobData.applied_date + '\n\n' +
  '## New Application\n' +
  '- Company: ' + jobData.company_name + '\n' +
  '- Role: ' + jobData.job_title + '\n' +
  '- Location: ' + jobData.location + '\n' +
  '- Date: ' + jobData.applied_date + '\n' +
  '- Method: Direct Application\n' +
  '- Status: Active\n';

return [{
  json: {
    ...jobData,
    tier5_status: 'complete',
    tracking_content: trackingContent,
    analytics_content: analyticsContent,
    followup_day3: fu1Date,
    followup_day7: fu2Date,
    followup_day30: fu3Date,
    followup_day90: fu4Date
  }
}];

// CHANGE #1: Fixed token access - process.env instead of $env
const githubToken = process.env.GITHUB_TOKEN || '';

// Collect all tier data from all parallel branches (Merge Results node)
const allItems = $input.all();
let jobData = {};
for (const item of allItems) {
  jobData = Object.assign({}, jobData, item.json);
}

if (!githubToken) {
  console.log('Warning: GITHUB_TOKEN not set, skipping git commit');
  return [{ json: Object.assign({}, jobData, { git_status: 'skipped' }) }];
}

const owner = 'odeliyach';
const repo = 'job-search-data';
const apiBase = 'https://api.github.com';
const headers = {
  'Authorization': 'token ' + githubToken,
  'Accept': 'application/vnd.github.v3+json',
  'Content-Type': 'application/json'
};

async function apiRequest(method, path, body) {
  return await $helpers.httpRequest({
    method: method,
    url: apiBase + path,
    headers: headers,
    body: body,
  });
}

// Auto-create folder structure based on application status
const statusFolder = 'Active';
const vaultBase = 'Obsidian_Vault/' + statusFolder + '/' + jobData.year + '/' + jobData.month + '/' + jobData.folder_name;
const legacyBase = jobData.year + '/' + jobData.month + '/' + jobData.folder_name;

try {
  const refData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/git/refs/heads/main');
  const currentSha = refData.object.sha;
  const commitData = await apiRequest('GET', '/repos/' + owner + '/' + repo + '/git/commits/' + currentSha);
  const treeSha = commitData.tree.sha;

  const filesToCommit = [];

  const contentMap = {
    'metadata.md': jobData.metadata_content,
    'resume.md': jobData.resume_content,
    'cover_letter.md': jobData.cover_letter_content,
    'cold_email.md': jobData.cold_email_content,
    'company_research.md': jobData.company_research_content,
    'personal_angle.md': jobData.personal_angle_content,
    'interview_prep.md': jobData.interview_prep_content,
    'portfolio_matching.md': jobData.portfolio_content,
    'tracking.md': jobData.tracking_content,
    'ats_optimization.md': jobData.ats_content
  };

  // Create each blob once, then add to both Obsidian_Vault and legacy paths
  for (const [fileName, content] of Object.entries(contentMap)) {
    if (!content) continue;
    try {
      const blobData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/blobs', {
        content: Buffer.from(content).toString('base64'),
        encoding: 'base64'
      });
      const blobSha = blobData.sha;
      // Obsidian_Vault path (for Obsidian Git plugin sync)
      filesToCommit.push({ path: vaultBase + '/' + fileName, mode: '100644', type: 'blob', sha: blobSha });
      // Legacy path (backwards compatibility)
      filesToCommit.push({ path: legacyBase + '/' + fileName, mode: '100644', type: 'blob', sha: blobSha });
    } catch (e) {
      console.error('Error processing file ' + fileName + ': ' + e.message);
    }
  }

  if (jobData.analytics_content) {
    try {
      const blobData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/blobs', {
        content: Buffer.from(jobData.analytics_content).toString('base64'),
        encoding: 'base64'
      });
      filesToCommit.push({ path: 'analytics.md', mode: '100644', type: 'blob', sha: blobData.sha });
    } catch (e) {
      console.error('Error processing analytics.md: ' + e.message);
    }
  }

  if (filesToCommit.length === 0) {
    return [{ json: Object.assign({}, jobData, { git_status: 'skipped', git_note: 'No content to commit' }) }];
  }

  const newTreeData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/trees', {
    base_tree: treeSha,
    tree: filesToCommit
  });

  const commitMessage = 'Job application: ' + jobData.company_name + ' - ' + jobData.job_title + ' - ' + jobData.applied_date;
  const newCommitData = await apiRequest('POST', '/repos/' + owner + '/' + repo + '/git/commits', {
    message: commitMessage,
    tree: newTreeData.sha,
    parents: [currentSha],
    author: {
      name: 'Odeliya Charitonova',
      email: 'odaliya12@gmail.com',
      date: new Date().toISOString()
    }
  });

  await apiRequest('PATCH', '/repos/' + owner + '/' + repo + '/git/refs/heads/main', {
    sha: newCommitData.sha,
    force: false
  });

  return [{ json: Object.assign({}, jobData, { git_status: 'success', commit_sha: newCommitData.sha, vault_path: vaultBase }) }];

} catch (e) {
  console.error('Git commit failed: ' + e.message);
  return [{ json: Object.assign({}, jobData, { git_status: 'error', git_error: e.message }) }];
}
